function ConvertFrom-EbgAAGUIDText {
    [CmdletBinding()]
    param([AllowNull()][string] $Text)

    if ([string]::IsNullOrWhiteSpace($Text)) { return @() }

    $matches = [regex]::Matches($Text, '[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}')
    $values = @($matches | ForEach-Object { $_.Value.ToLowerInvariant() } | Select-Object -Unique)
    return $values
}
function ConvertTo-BreakGlassUpn {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)][string] $Prefix,
        [Parameter(Mandatory)][string] $OnMicrosoftDomain
    )

    $cleanPrefix = $Prefix.Trim()
    if ([string]::IsNullOrWhiteSpace($cleanPrefix)) { throw 'UPN prefix må ikke være tomt.' }
    if ($cleanPrefix -match '@') { throw 'Angiv kun UPN prefix, ikke et fuldt UPN.' }
    if ($cleanPrefix -notmatch '^[A-Za-z0-9._-]+$') { throw 'UPN prefix må kun indeholde bogstaver, tal, punktum, bindestreg og underscore.' }
    return ('{0}@{1}' -f $cleanPrefix, $OnMicrosoftDomain.ToLowerInvariant())
}
function ConvertTo-EbgNeutralUserPrefix {
    [CmdletBinding()]
    param([Parameter(Mandatory)][string] $DisplayName)

    $prefix = $DisplayName.Trim().ToLowerInvariant()
    $prefix = [regex]::Replace($prefix, '[^a-z0-9]+', '.')
    $prefix = $prefix.Trim('.')
    if ([string]::IsNullOrWhiteSpace($prefix)) {
        throw 'Kunne ikke lave et neutralt UPN prefix fra display name.'
    }
    return $prefix
}
function ConvertTo-EbgPlainHashtable {
    [CmdletBinding()]
    param([AllowNull()] $InputObject)

    if ($null -eq $InputObject) { return $null }
    if ($InputObject -is [string] -or $InputObject.GetType().IsPrimitive) { return $InputObject }
    if ($InputObject -is [System.Collections.IEnumerable] -and -not ($InputObject -is [System.Collections.IDictionary])) {
        $items = @()
        foreach ($item in $InputObject) { $items += ConvertTo-EbgPlainHashtable -InputObject $item }
        return $items
    }
    $hash = @{}
    foreach ($property in $InputObject.PSObject.Properties) {
        $hash[$property.Name] = ConvertTo-EbgPlainHashtable -InputObject $property.Value
    }
    return $hash
}
function ConvertTo-EbgRedactedError {
    [CmdletBinding()]
    param([AllowNull()] $ErrorRecord)

    $text = if ($null -eq $ErrorRecord) { '' } else { [string] $ErrorRecord }
    $patterns = @(
        '(?i)Authorization:\s*Bearer\s+[A-Za-z0-9\._\-]+',
        '(?i)(access_token|refresh_token|client_secret|password)"?\s*[:=]\s*"[^"]+"',
        'eyJ[A-Za-z0-9_\-]+\.[A-Za-z0-9_\-]+\.[A-Za-z0-9_\-]+'
    )
    foreach ($pattern in $patterns) {
        $text = [regex]::Replace($text, $pattern, '[REDACTED]')
    }
    return $text
}
function Ensure-EbgAuthenticationStrength {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)][string] $DisplayName,
        [Parameter(Mandatory)][string] $Description,
        [Parameter(Mandatory)][string[]] $AllowedAAGUIDs,
        [Parameter(Mandatory)][bool] $Apply
    )

    $allowed = @($AllowedAAGUIDs | Where-Object { $_ } | ForEach-Object { $_.ToLowerInvariant() } | Select-Object -Unique)
    if ($allowed.Count -lt 1) {
        throw 'Der skal mindst være ét AAGUID før authentication strength kan oprettes.'
    }

    if (-not $Apply -or $sync.App.Mock) {
        return [pscustomobject]@{
            id = 'planned-auth-strength'
            displayName = $DisplayName
            allowedAAGUIDs = $allowed
            Status = if ($Apply) { 'Created' } else { 'PlannedCreate' }
        }
    }

    $existing = Get-EbgAuthenticationStrengthByName -DisplayName $DisplayName
    if (-not $existing) {
        Write-EbgLog -Message "Opretter authentication strength: $DisplayName"
        $body = @{
            displayName = $DisplayName
            description = $Description
            requirementsSatisfied = 'mfa'
            allowedCombinations = @('fido2')
            combinationConfigurations = @(
                @{
                    '@odata.type' = '#microsoft.graph.fido2CombinationConfiguration'
                    allowedAAGUIDs = $allowed
                    appliesToCombinations = @('fido2')
                }
            )
        }
        $created = Invoke-EbgGraphRequest -Method POST -Uri 'https://graph.microsoft.com/v1.0/identity/conditionalAccess/authenticationStrength/policies' -Body $body
        $created | Add-Member -MemberType NoteProperty -Name Status -Value 'Created' -Force
        $created | Add-Member -MemberType NoteProperty -Name allowedAAGUIDs -Value $allowed -Force
        return $created
    }

    $strengthId = [string](Get-EbgObjectPropertyValue -InputObject $existing -Name 'id')
    $configs = @(Get-EbgGraphCollection -Uri "https://graph.microsoft.com/v1.0/identity/conditionalAccess/authenticationStrength/policies/$strengthId/combinationConfigurations")
    $fidoConfig = $configs | Where-Object {
        $type = [string](Get-EbgObjectPropertyValue -InputObject $_ -Name '@odata.type')
        $applies = @(Get-EbgObjectPropertyValue -InputObject $_ -Name 'appliesToCombinations')
        $type -match 'fido2CombinationConfiguration' -or $applies -contains 'fido2'
    } | Select-Object -First 1

    if (-not $fidoConfig) {
        Write-EbgLog -Message "Tilføjer FIDO2 AAGUID restriction til authentication strength: $DisplayName"
        $body = @{
            '@odata.type' = '#microsoft.graph.fido2CombinationConfiguration'
            allowedAAGUIDs = $allowed
            appliesToCombinations = @('fido2')
        }
        Invoke-EbgGraphRequest -Method POST -Uri "https://graph.microsoft.com/v1.0/identity/conditionalAccess/authenticationStrength/policies/$strengthId/combinationConfigurations" -Body $body | Out-Null
        $existing | Add-Member -MemberType NoteProperty -Name Status -Value 'Updated' -Force
        $existing | Add-Member -MemberType NoteProperty -Name allowedAAGUIDs -Value $allowed -Force
        return $existing
    }

    $existingAAGUIDs = @(Get-EbgObjectPropertyValue -InputObject $fidoConfig -Name 'allowedAAGUIDs') | ForEach-Object { [string]$_ }
    $merged = @($existingAAGUIDs + $allowed | Where-Object { $_ } | ForEach-Object { $_.ToLowerInvariant() } | Select-Object -Unique)
    if (@($merged | Where-Object { $existingAAGUIDs -notcontains $_ }).Count -gt 0) {
        $configId = [string](Get-EbgObjectPropertyValue -InputObject $fidoConfig -Name 'id')
        Write-EbgLog -Message "Opdaterer AAGUID-listen på authentication strength: $DisplayName"
        Invoke-EbgGraphRequest -Method PATCH -Uri "https://graph.microsoft.com/v1.0/identity/conditionalAccess/authenticationStrength/policies/$strengthId/combinationConfigurations/$configId" -Body @{ allowedAAGUIDs = $merged } | Out-Null
        $status = 'Updated'
    }
    else {
        $status = 'AlreadyExists'
    }

    $existing | Add-Member -MemberType NoteProperty -Name Status -Value $status -Force
    $existing | Add-Member -MemberType NoteProperty -Name allowedAAGUIDs -Value $merged -Force
    return $existing
}
function Ensure-EbgBreakGlassCAPolicy {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)][string] $DisplayName,
        [string] $GroupId = '',
        [string[]] $UserIds = @(),
        [Parameter(Mandatory)][string] $AuthenticationStrengthId,
        [bool] $Enabled = $false,
        [Parameter(Mandatory)][bool] $Apply
    )

    $targetUsers = @($UserIds | Where-Object { -not [string]::IsNullOrWhiteSpace([string]$_) })
    if ($targetUsers.Count -lt 1 -and [string]::IsNullOrWhiteSpace($GroupId)) { throw 'Der skal angives mindst én break-glass konto eller gruppe før CA-politikken kan oprettes.' }
    if ([string]::IsNullOrWhiteSpace($AuthenticationStrengthId)) { throw 'Authentication strength skal have et Object ID før CA-politikken kan oprettes.' }

    $state = if ($Enabled) { 'enabled' } else { 'disabled' }
    if (-not $Apply -or $sync.App.Mock) {
        return [pscustomobject]@{ id='planned-ca-policy'; displayName=$DisplayName; state=$state; Status=if($Apply){'Created'}else{'PlannedCreate'} }
    }

    $existing = @(Get-EbgConditionalAccessPolicies | Where-Object { [string](Get-EbgObjectPropertyValue -InputObject $_ -Name 'displayName') -eq $DisplayName }) | Select-Object -First 1
    if ($existing) {
        $existing | Add-Member -MemberType NoteProperty -Name Status -Value 'AlreadyExists' -Force
        return $existing
    }

    Write-EbgLog -Message "Opretter dedikeret BreakGlass FIDO2 CA-policy: $DisplayName"
    $body = @{
        displayName = $DisplayName
        state = $state
        conditions = @{
            users = @{
                includeUsers = if ($targetUsers.Count -gt 0) { $targetUsers } else { @() }
                includeGroups = if ($targetUsers.Count -lt 1 -and -not [string]::IsNullOrWhiteSpace($GroupId)) { @($GroupId) } else { @() }
                excludeUsers = @()
                excludeGroups = @()
            }
            applications = @{
                includeApplications = @('All')
                excludeApplications = @()
            }
            clientAppTypes = @('all')
        }
        grantControls = @{
            operator = 'OR'
            authenticationStrength = @{
                id = $AuthenticationStrengthId
            }
        }
    }
    $created = Invoke-EbgGraphRequest -Method POST -Uri 'https://graph.microsoft.com/v1.0/identity/conditionalAccess/policies' -Body $body
    $created | Add-Member -MemberType NoteProperty -Name Status -Value 'Created' -Force
    return $created
}
function Ensure-EbgGlobalAdministratorAssignment {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)] $User,
        [Parameter(Mandatory)] $RoleDefinition,
        [Parameter(Mandatory)][bool] $Apply
    )

    $userId = [string](Get-EbgObjectPropertyValue -InputObject $User -Name 'id')
    $upn = [string](Get-EbgObjectPropertyValue -InputObject $User -Name 'userPrincipalName')
    $roleDefinitionId = [string](Get-EbgObjectPropertyValue -InputObject $RoleDefinition -Name 'id')
    $roleName = [string](Get-EbgObjectPropertyValue -InputObject $RoleDefinition -Name 'displayName')

    if ([string]::IsNullOrWhiteSpace($userId) -or [string]::IsNullOrWhiteSpace($roleDefinitionId)) {
        return [pscustomobject]@{
            UserPrincipalName = $upn
            Role = $roleName
            Scope = '/'
            Status = 'Skipped'
            Detail = 'User or role definition missing.'
        }
    }

    if ($sync.App.Mock -or $userId -like 'mock-*') {
        Write-EbgLog -Level PASS -Message "Administratorrolle håndteret: $upn -> $roleName"
        return [pscustomobject]@{
            UserPrincipalName = $upn
            Role = $roleName
            Scope = '/'
            Status = if ($Apply) { 'Assigned' } else { 'Planned' }
            Detail = ''
        }
    }

    if (-not $Apply) {
        return [pscustomobject]@{
            UserPrincipalName = $upn
            Role = $roleName
            Scope = '/'
            Status = 'Planned'
            Detail = ''
        }
    }

    $body = @{
        principalId = $userId
        roleDefinitionId = $roleDefinitionId
        directoryScopeId = '/'
    }
    Write-EbgLog -Message "Tildeler $roleName til $upn..."
    try {
        Invoke-EbgGraphRequest -Method POST -Uri 'https://graph.microsoft.com/v1.0/roleManagement/directory/roleAssignments' -Body $body | Out-Null
        Write-EbgLog -Level PASS -Message "Administratorrolle tildelt: $upn -> $roleName"
        return [pscustomobject]@{
            UserPrincipalName = $upn
            Role = $roleName
            Scope = '/'
            Status = 'Assigned'
            Detail = ''
        }
    }
    catch {
        $message = [string]$_
        if ($message -match 'already exist|already exists|conflicting object|RoleAssignmentExists|role assignment already') {
            Write-EbgLog -Level PASS -Message "Administratorrolle findes allerede: $upn -> $roleName"
            return [pscustomobject]@{
                UserPrincipalName = $upn
                Role = $roleName
                Scope = '/'
                Status = 'AlreadyAssigned'
                Detail = ''
            }
        }
        throw
    }
}
function Ensure-EbgGroupMember {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)] $Group,
        [Parameter(Mandatory)] $User,
        [Parameter(Mandatory)][bool] $Apply
    )

    $groupId = [string](Get-EbgObjectPropertyValue -InputObject $Group -Name 'id')
    $userId = [string](Get-EbgObjectPropertyValue -InputObject $User -Name 'id')
    $upn = [string](Get-EbgObjectPropertyValue -InputObject $User -Name 'userPrincipalName')
    $groupName = [string](Get-EbgObjectPropertyValue -InputObject $Group -Name 'displayName')
    if ([string]::IsNullOrWhiteSpace($groupId) -or [string]::IsNullOrWhiteSpace($userId)) {
        return [pscustomobject]@{ UserPrincipalName = $upn; Group = $groupName; Status = 'Skipped'; Detail = 'Group or user missing.' }
    }
    if ($sync.App.Mock -or $groupId -like 'planned-*' -or $userId -like 'mock-*') {
        Write-EbgLog -Level PASS -Message "Gruppemedlemskab håndteret: $upn -> $groupName"
        return [pscustomobject]@{ UserPrincipalName = $upn; Group = $groupName; Status = if ($Apply) { 'Added' } else { 'Planned' } }
    }
    if (-not $Apply) {
        return [pscustomobject]@{ UserPrincipalName = $upn; Group = $groupName; Status = 'Planned' }
    }
    Write-EbgLog -Message "Tilføjer $upn til gruppen $groupName..."
    try {
        Invoke-EbgGraphRequest -Method POST -Uri "https://graph.microsoft.com/v1.0/groups/$groupId/members/`$ref" -Body @{ '@odata.id' = "https://graph.microsoft.com/v1.0/directoryObjects/$userId" } | Out-Null
        Write-EbgLog -Level PASS -Message "Gruppemedlemskab tilføjet: $upn -> $groupName"
        return [pscustomobject]@{ UserPrincipalName = $upn; Group = $groupName; Status = 'Added' }
    }
    catch {
        $message = [string]$_
        if ($message -match 'already exist|already exists|added object references already exist|object references already exist') {
            Write-EbgLog -Level PASS -Message "Gruppemedlemskab findes allerede: $upn -> $groupName"
            return [pscustomobject]@{ UserPrincipalName = $upn; Group = $groupName; Status = 'AlreadyMember' }
        }
        throw
    }
}
function Ensure-EbgSecurityGroup {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)][string] $DisplayName,
        [Parameter(Mandatory)][string] $Description,
        [Parameter(Mandatory)][bool] $CreateIfMissing,
        [Parameter(Mandatory)][bool] $Apply
    )

    $group = Get-EbgGroupByDisplayName -DisplayName $DisplayName
    if ($group) {
        $group | Add-Member -MemberType NoteProperty -Name EnsureStatus -Value 'AlreadyExists' -Force
        $currentDescription = [string](Get-EbgObjectPropertyValue -InputObject $group -Name 'description')
        if ($currentDescription -ne $Description) {
            if ($Apply) {
                Invoke-EbgGraphRequest -Method PATCH -Uri "https://graph.microsoft.com/v1.0/groups/$($group.id)" -Body @{ description = $Description } | Out-Null
                $group.description = $Description
                $group.EnsureStatus = 'UpdatedDescription'
            }
            else {
                $group.EnsureStatus = 'PlannedDescriptionUpdate'
            }
        }
        return $group
    }
    if (-not $CreateIfMissing) {
        return [pscustomobject]@{ id = ''; displayName = $DisplayName; EnsureStatus = 'SkippedMissing' }
    }
    if (-not $Apply) {
        return [pscustomobject]@{ id = 'planned-group'; displayName = $DisplayName; description = $Description; EnsureStatus = 'PlannedCreate' }
    }
    $created = New-EbgSecurityGroup -DisplayName $DisplayName -Description $Description
    $created | Add-Member -MemberType NoteProperty -Name EnsureStatus -Value 'Created' -Force
    return $created
}
function Export-EbgJsonSafe {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)] $InputObject,
        [Parameter(Mandatory)][string] $Path,
        [int] $Depth = 20
    )

    $folder = Split-Path -Parent $Path
    if ($folder) { New-Item -ItemType Directory -Force -Path $folder | Out-Null }
    $InputObject | ConvertTo-Json -Depth $Depth | Set-Content -LiteralPath $Path -Encoding UTF8
    return $Path
}
function Get-EbgActiveGlobalAdministrators {
    [CmdletBinding()]
    param()

    if ($sync.App.Mock) {
        return @(
            [pscustomobject]@{
                id = 'mock-ga-1'
                displayName = 'Mock Global Admin'
                userPrincipalName = 'mock.globaladmin@contoso.onmicrosoft.com'
                accountEnabled = $true
                assignmentType = 'Direct Global Administrator assignment'
            }
        )
    }

    $role = Get-EbgGlobalAdministratorRoleDefinition
    $roleId = [string](Get-EbgObjectPropertyValue -InputObject $role -Name 'id')
    if ([string]::IsNullOrWhiteSpace($roleId)) {
        return @()
    }

    $filter = [uri]::EscapeDataString("roleDefinitionId eq '$roleId'")
    $assignments = @(Get-EbgGraphCollection -Uri "https://graph.microsoft.com/v1.0/roleManagement/directory/roleAssignments?`$filter=$filter&`$select=id,principalId,roleDefinitionId,directoryScopeId")
    $admins = New-Object System.Collections.Generic.List[object]

    foreach ($assignment in $assignments) {
        $principalId = [string](Get-EbgObjectPropertyValue -InputObject $assignment -Name 'principalId')
        if ([string]::IsNullOrWhiteSpace($principalId)) { continue }

        try {
            $user = Invoke-EbgGraphRequest -Method GET -Uri ("https://graph.microsoft.com/v1.0/users/{0}?`$select=id,displayName,userPrincipalName,accountEnabled" -f [uri]::EscapeDataString($principalId)) -SuppressNotFoundLog
            $enabled = [bool](Get-EbgObjectPropertyValue -InputObject $user -Name 'accountEnabled')
            if (-not $enabled) { continue }

            $admins.Add([pscustomobject]@{
                id = [string](Get-EbgObjectPropertyValue -InputObject $user -Name 'id')
                displayName = [string](Get-EbgObjectPropertyValue -InputObject $user -Name 'displayName')
                userPrincipalName = [string](Get-EbgObjectPropertyValue -InputObject $user -Name 'userPrincipalName')
                accountEnabled = $enabled
                assignmentType = 'Direct Global Administrator assignment'
            })
        }
        catch {
            Write-EbgLog -Level WARN -Message "Springer Global Administrator principal over, fordi den ikke kunne læses som aktiv bruger: $principalId"
        }
    }

    return @($admins | Sort-Object userPrincipalName -Unique)
}
function Get-EbgAuthenticationStrengthByName {
    [CmdletBinding()]
    param([Parameter(Mandatory)][string] $DisplayName)

    if ($sync.App.Mock) {
        if ($DisplayName -eq $sync.configs.appsettings.authenticationStrengthName) {
            return $null
        }
        return $null
    }

    $filter = [uri]::EscapeDataString("displayName eq '$($DisplayName.Replace("'", "''"))'")
    $policies = @(Get-EbgGraphCollection -Uri "https://graph.microsoft.com/v1.0/identity/conditionalAccess/authenticationStrength/policies?`$filter=$filter")
    return $policies | Select-Object -First 1
}
