function Invoke-EbgGraphRequest {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)][ValidateSet('GET','POST','PATCH','DELETE')][string] $Method,
        [Parameter(Mandatory)][string] $Uri,
        [AllowNull()] $Body = $null,
        [switch] $SuppressNotFoundLog
    )

    if ($sync.App.Mock) {
        throw 'Mock mode should not call Microsoft Graph.'
    }
    $params = @{
        Method      = $Method
        Uri         = $Uri
        ErrorAction = 'Stop'
    }
    if ($null -ne $Body) {
        $params.Body = if ($Body -is [string]) { $Body } else { ($Body | ConvertTo-Json -Depth 30) }
        $params.ContentType = 'application/json'
    }
    try {
        return Invoke-MgGraphRequest @params
    }
    catch {
        $message = [string]$_
        $isNotFound = $message -match '404|Request_ResourceNotFound|Resource .* does not exist'
        if (-not ($SuppressNotFoundLog -and $isNotFound)) {
            Write-EbgLog -Level ERROR -Message (ConvertTo-EbgRedactedError -ErrorRecord $_)
        }
        throw
    }
}
function Invoke-EbgRunspace {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)][scriptblock] $ScriptBlock,
        [object[]] $ArgumentList = @()
    )

    if ($sync.UI.ProcessRunning) {
        [System.Windows.MessageBox]::Show('Der kører allerede en opgave. Vent til den er færdig.', $sync.App.Name, 'OK', 'Information') | Out-Null
        return
    }
    $sync.UI.ProcessRunning = $true
    if ($sync.WPFProgressBar) {
        [void]$sync.WPFProgressBar.Dispatcher.Invoke([System.Action]{ $sync.WPFProgressBar.IsIndeterminate = $true })
    }
    $ps = [PowerShell]::Create()
    $ps.RunspacePool = $sync.Runspace
    [void]$ps.AddScript({
        param($innerScript, $innerArgs)
        try {
            & $innerScript @innerArgs
        }
        catch {
            $friendly = 'Der opstod en fejl. Se logfilen for tekniske detaljer.'
            Write-EbgLog -Level ERROR -Message (ConvertTo-EbgRedactedError -ErrorRecord $_)
            $sync.State.Errors += $friendly
            if ($sync.Form) {
                [void]$sync.Form.Dispatcher.Invoke([System.Action]{
                    $sync.WPFStatusText.Text = $friendly
                    [System.Windows.MessageBox]::Show($friendly, $sync.App.Name, 'OK', 'Error') | Out-Null
                })
            }
        }
        finally {
            $sync.UI.ProcessRunning = $false
            if ($sync.Form) {
                [void]$sync.Form.Dispatcher.Invoke([System.Action]{
                    $sync.WPFProgressBar.IsIndeterminate = $false
                    Update-EbgUIState | Out-Null
                })
            }
        }
    }).AddArgument($ScriptBlock).AddArgument($ArgumentList) | Out-Null
    [void]$ps.BeginInvoke()
}
function New-BreakGlassUser {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)][string] $DisplayName,
        [Parameter(Mandatory)][string] $UserPrincipalName,
        [Parameter(Mandatory)][string] $Password
    )

    if ($sync.App.Mock) {
        return [pscustomobject]@{ id = "mock-$($UserPrincipalName.Split('@')[0])"; displayName = $DisplayName; userPrincipalName = $UserPrincipalName; accountEnabled = $true; EnsureStatus = 'Created' }
    }
    $mailNickname = ($UserPrincipalName.Split('@')[0] -replace '[^A-Za-z0-9]', '')
    $body = @{
        accountEnabled    = $true
        displayName       = $DisplayName
        mailNickname      = $mailNickname
        userPrincipalName = $UserPrincipalName
        passwordProfile   = @{
            forceChangePasswordNextSignIn = $false
            password = $Password
        }
    }
    Invoke-EbgGraphRequest -Method POST -Uri 'https://graph.microsoft.com/v1.0/users' -Body $body | Out-Null
    $user = Get-EbgUserByUpn -UserPrincipalName $UserPrincipalName
    $user | Add-Member -MemberType NoteProperty -Name EnsureStatus -Value 'Created' -Force
    return $user
}
function New-EbgHandoffHtml {
