    <tr><th>Backup path</th><td>$(ConvertTo-EbgHtmlValue (Get-EbgObjectPropertyValue -InputObject $Result -Name 'CABackupPath'))</td></tr>
  </table>
  <h3>Policies ændret</h3>
  $changedTable
  <h3>Policies der allerede ekskluderede gruppen</h3>
  $alreadyTable
  <h3>Policies der fejlede</h3>
  $failedTable
  <h2>Advarsler/fejl</h2>
  $warnings
  <h2>Manuelle næste steps</h2>
  <ol>
    <li>Gem de genererede adgangskoder/TAP-koder sikkert efter intern/kundeprocedure og fjern lokale kopier efter handoff.</li>
    <li>Registrer to separate FIDO2 security keys pr. break-glass konto.</li>
    <li>Verificér at begge break-glass konti har direkte Global Administrator rolle.</li>
    <li>Hvis administrator-SSPR blev deaktiveret, vent op til 60 minutter og test derefter FIDO2/TAP onboarding igen.</li>
    <li>Verificér at begge break-glass konti kan logge ind.</li>
    <li>Den dedikerede BreakGlass FIDO2 CA-policy oprettes som disabled. Valider sign-in logs og authentication strength før den sættes til enabled.</li>
    <li>Verificér at kontiene er medlem af CA-BreakGlass-Exclude.</li>
    <li>Verificér at gruppen er ekskluderet fra de ønskede Conditional Access-politikker, hvis funktionen blev valgt.</li>
    <li>Dokumentér hvor credentials opbevares.</li>
    <li>Aftal periodisk test/review med kunden.</li>
  </ol>
</body>
</html>
"@
    Set-Content -LiteralPath $path -Value $html -Encoding UTF8
    $sync.State.HandoffPath = $path
    return $path
}
function New-EbgOutputFolder {
    [CmdletBinding()]
    param([Parameter(Mandatory)][string] $TenantId)

    $safeTenant = if ([string]::IsNullOrWhiteSpace($TenantId)) { 'UnknownTenant' } else { $TenantId }
    $folder = Join-Path -Path $sync.App.OutputRoot -ChildPath ('BreakGlass-{0}-{1}' -f $safeTenant, (Get-Date -Format 'yyyyMMdd-HHmmss'))
    New-Item -ItemType Directory -Force -Path $folder | Out-Null
    $sync.State.OutputFolder = $folder
    return $folder
}
function New-EbgPlanObject {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)][hashtable] $Config,
        [AllowNull()] $Discovery = $null
    )

    $tenant = Get-EbgTenantInfo
    $upn1 = ConvertTo-BreakGlassUpn -Prefix $Config.UserPrefix1 -OnMicrosoftDomain $tenant.OnMicrosoftDomain
    $upn2 = ConvertTo-BreakGlassUpn -Prefix $Config.UserPrefix2 -OnMicrosoftDomain $tenant.OnMicrosoftDomain
    $user1 = if ($Discovery) { $Discovery.User1 } else { Get-EbgUserByUpn -UserPrincipalName $upn1 }
    $user2 = if ($Discovery) { $Discovery.User2 } else { Get-EbgUserByUpn -UserPrincipalName $upn2 }
    $group = if ($Discovery) { $Discovery.Group } else { Get-EbgGroupByDisplayName -DisplayName $Config.GroupName }
    $policies = if ($Discovery) { @($Discovery.CAPolicies) } else { @(Get-EbgConditionalAccessPolicies) }
    $authorizationPolicy = Get-EbgAuthorizationPolicy
    $adminSSPREnabled = [bool](Get-EbgObjectPropertyValue -InputObject $authorizationPolicy -Name 'allowedToUseSSPR')

    $alreadyExcluded = @()
    $toPatch = @()
    if ($group -and $group.id) {
        foreach ($policy in $policies) {
            $excludeGroups = @(Get-EbgObjectPropertyValue -InputObject (Get-EbgObjectPropertyValue -InputObject (Get-EbgObjectPropertyValue -InputObject $policy -Name 'conditions') -Name 'users') -Name 'excludeGroups')
            if ($excludeGroups -contains $group.id) { $alreadyExcluded += $policy }
            elseif ($Config.PatchCAPolicies) { $toPatch += $policy }
        }
    }
    elseif ($Config.PatchCAPolicies) {
        $toPatch = @($policies)
    }

    $warnings = @()
    if ($user1) { $warnings += 'Konto 1 findes allerede. Password bliver ikke ændret automatisk.' }
    if ($user2) { $warnings += 'Konto 2 findes allerede. Password bliver ikke ændret automatisk.' }
    $warnings += 'Begge break-glass konti får direkte Global Administrator rolle på tenant scope (/).'
    if ($Config.DisableAdminSSPR) { $warnings += 'Administrator-SSPR deaktiveres tenant-wide og kan tage op til 60 minutter at slå igennem.' }
    $warnings += 'Phase 1 opretter Temporary Access Pass for begge konti: one-time use = Yes, duration = 2 hours.'
    $warnings += 'Phase 1b kræver manuel registrering af to FIDO2 security keys pr. konto.'
    $warnings += 'Phase 2 opretter/opdaterer BreakGlass-FIDO2 authentication strength og en dedikeret CA-policy som disabled.'
    if ($Config.PatchCAPolicies) { $warnings += 'Eksisterende Conditional Access-politikker ændres. Backup oprettes før ændringer.' }
    if (@($Config.AAGUIDs).Count -lt 1) { $warnings += 'AAGUIDs hentes normalt automatisk i Phase 2 efter FIDO2 keys er registreret.' }

    $outputFolder = if ($sync.State.OutputFolder) { $sync.State.OutputFolder } else { Join-Path $sync.App.OutputRoot ('BreakGlass-{0}-<timestamp>' -f $tenant.TenantId) }
    $plan = [pscustomobject]@{
        TenantId                  = $tenant.TenantId
        TenantDisplayName         = $tenant.TenantDisplayName
        OnMicrosoftDomain         = $tenant.OnMicrosoftDomain
        Account1DisplayName       = $Config.DisplayName1
        Account1UPN               = $upn1
        Account1Status            = if ($user1) { 'Eksisterer allerede' } elseif ($Config.CreateUsers) { 'Oprettes' } else { 'Springes over' }
        Account2DisplayName       = $Config.DisplayName2
        Account2UPN               = $upn2
        Account2Status            = if ($user2) { 'Eksisterer allerede' } elseif ($Config.CreateUsers) { 'Oprettes' } else { 'Springes over' }
        GroupName                 = $Config.GroupName
        GroupStatus               = if ($group) { 'Eksisterer allerede' } elseif ($Config.CreateGroup) { 'Oprettes' } else { 'Springes over' }
        AddAccountsToGroup        = [bool]$Config.AddUsersToGroup
        AssignGlobalAdministrator = $true
        RoleAssignmentScope       = '/'
        DisableAdminSSPR          = [bool]$Config.DisableAdminSSPR
        CurrentAdminSSPREnabled   = $adminSSPREnabled
        PlannedAdminSSPRStatus    = if ($Config.DisableAdminSSPR) { if ($adminSSPREnabled) { 'Deaktiveres' } else { 'Allerede deaktiveret' } } else { 'Uændret' }
        AuthenticationStrengthName = $Config.AuthenticationStrengthName
        AuthenticationStrengthAAGUIDs = @($Config.AAGUIDs)
        TemporaryAccessPassStatus    = 'Phase 1: oprettes for begge konti, one-time use, 2 timer'
        AuthenticationStrengthStatus = if (@($Config.AAGUIDs).Count -gt 0) { 'Phase 2: oprettes/opdateres med angivne + fundne AAGUIDs' } else { 'Phase 2: oprettes/opdateres efter automatisk AAGUID refresh' }
        BreakGlassCAPolicyName    = $Config.BreakGlassCAPolicyName
        BreakGlassCAPolicyStatus  = 'Phase 2: oprettes disabled og tildeles direkte til de 2 konti'
        ConditionalAccessCount    = @($policies).Count
        PatchConditionalAccess    = [bool]$Config.PatchCAPolicies
        CAPoliciesToChange        = @($toPatch | Select-Object id,displayName,state)
        CAPoliciesAlreadyExcluded = @($alreadyExcluded | Select-Object id,displayName,state)
        OutputFolder              = $outputFolder
        HandoffPath               = Join-Path $outputFolder 'handoff.html'
        Warnings                  = $warnings
        GeneratedAt               = (Get-Date).ToString('o')
    }
    $sync.State.Plan = $plan
    return $plan
}
function New-EbgRandomPassword {
    [CmdletBinding()]
    param([int] $Length = 28)

    if ($Length -lt 24) { $Length = 24 }
    $upper = 'ABCDEFGHJKLMNPQRSTUVWXYZ'
    $lower = 'abcdefghijkmnopqrstuvwxyz'
    $digits = '23456789'
    $symbols = '!#$%&*+-=?@_'
    $all = ($upper + $lower + $digits + $symbols).ToCharArray()
    $rng = [System.Security.Cryptography.RandomNumberGenerator]::Create()
    function Get-RandomChar([char[]] $Chars) {
        $bytes = [byte[]]::new(4)
        $rng.GetBytes($bytes)
        return $Chars[[BitConverter]::ToUInt32($bytes, 0) % $Chars.Count]
    }
    $chars = @(
        (Get-RandomChar $upper.ToCharArray()),
        (Get-RandomChar $lower.ToCharArray()),
        (Get-RandomChar $digits.ToCharArray()),
        (Get-RandomChar $symbols.ToCharArray())
    )
    while ($chars.Count -lt $Length) { $chars += Get-RandomChar $all }
    $shuffled = $chars | Sort-Object { Get-Random }
    return -join $shuffled
}
function New-EbgSecurityGroup {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)][string] $DisplayName,
        [Parameter(Mandatory)][string] $Description
    )

    if ($sync.App.Mock) {
        return [pscustomobject]@{ id = 'mock-ca-exclude-group'; displayName = $DisplayName; description = $Description; mailEnabled = $false; securityEnabled = $true; groupTypes = @(); EnsureStatus = 'Created' }
    }
    $body = @{
        displayName     = $DisplayName
        description     = $Description
        mailEnabled     = $false
        mailNickname    = 'CABreakGlassExclude'
        securityEnabled = $true
        groupTypes      = @()
    }
    Invoke-EbgGraphRequest -Method POST -Uri 'https://graph.microsoft.com/v1.0/groups' -Body $body | Out-Null
    return Get-EbgGroupByDisplayName -DisplayName $DisplayName
}
function New-EbgTemporaryAccessPass {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)] $User,
        [int] $LifetimeInMinutes = 120,
        [bool] $IsUsableOnce = $true,
        [Parameter(Mandatory)][bool] $Apply
    )

    $userId = [string](Get-EbgObjectPropertyValue -InputObject $User -Name 'id')
    $upn = [string](Get-EbgObjectPropertyValue -InputObject $User -Name 'userPrincipalName')
    if ([string]::IsNullOrWhiteSpace($userId)) { throw "Kan ikke oprette TAP for $upn, fordi brugeren mangler Object ID." }

    if (-not $Apply -or $sync.App.Mock) {
        return [pscustomobject]@{
            id = 'planned-tap'
            UserPrincipalName = $upn
            temporaryAccessPass = if ($Apply) { 'MOCK-TAP-12345678' } else { '' }
            lifetimeInMinutes = $LifetimeInMinutes
            isUsableOnce = $IsUsableOnce
            createdDateTime = (Get-Date).ToString('o')
            Status = if ($Apply) { 'Created' } else { 'PlannedCreate' }
        }
    }

    Write-EbgLog -Message "Opretter Temporary Access Pass for $upn (one-time use: $IsUsableOnce, lifetime: $LifetimeInMinutes minutter)."
    $body = @{
        lifetimeInMinutes = $LifetimeInMinutes
        isUsableOnce = $IsUsableOnce
    }
    $created = Invoke-EbgGraphRequest -Method POST -Uri "https://graph.microsoft.com/v1.0/users/$userId/authentication/temporaryAccessPassMethods" -Body $body
    $created | Add-Member -MemberType NoteProperty -Name UserPrincipalName -Value $upn -Force
    $created | Add-Member -MemberType NoteProperty -Name lifetimeInMinutes -Value $LifetimeInMinutes -Force
    $created | Add-Member -MemberType NoteProperty -Name isUsableOnce -Value $IsUsableOnce -Force
    $created | Add-Member -MemberType NoteProperty -Name Status -Value 'Created' -Force
    return $created
}
function Remove-EbgTemporaryAccessPassMethods {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)][object[]] $Users,
        [Parameter(Mandatory)][bool] $Apply
    )

    $results = [System.Collections.Generic.List[object]]::new()
    foreach ($user in $Users) {
        $userId = [string](Get-EbgObjectPropertyValue -InputObject $user -Name 'id')
        $upn = [string](Get-EbgObjectPropertyValue -InputObject $user -Name 'userPrincipalName')
        if ([string]::IsNullOrWhiteSpace($userId)) { continue }

        $methods = @(Get-EbgTemporaryAccessPassMethods -User $user)
        if ($methods.Count -lt 1) {
            $results.Add([pscustomobject]@{ UserPrincipalName = $upn; MethodId = ''; Status = 'NotFound' })
            continue
        }

        foreach ($method in $methods) {
            $methodId = [string](Get-EbgObjectPropertyValue -InputObject $method -Name 'id')
            if (-not $Apply -or $sync.App.Mock) {
                $results.Add([pscustomobject]@{ UserPrincipalName = $upn; MethodId = $methodId; Status = if($Apply){'Deleted'}else{'PlannedDelete'} })
                continue
            }
            Invoke-EbgGraphRequest -Method DELETE -Uri "https://graph.microsoft.com/v1.0/users/$userId/authentication/temporaryAccessPassMethods/$methodId" | Out-Null
            $results.Add([pscustomobject]@{ UserPrincipalName = $upn; MethodId = $methodId; Status = 'Deleted' })
            Write-EbgLog -Level PASS -Message "Temporary Access Pass slettet for $upn."
        }
    }
    return @($results)
}
